external_knowledge:
- 'Stars in the night sky' metaphorically refers to financial instruments being of significant interest;
- 'Vigilant analysts' represents users with the role of 'analyst';
- 'Under the spotlight of attention' refers to financial instruments with active alerts (alert_type is not null).

sql:
SELECT t.*
FROM trades t
JOIN alerts a ON t.user_id = a.user_id AND t.instrument_id = a.instrument_id;

SELECT symbol, name, sector, industry, market_cap, last_price
FROM financial_instruments
ORDER BY market_cap DESC, last_price DESC;

SELECT amount 
FROM dividends 
WHERE instrument_id = 1;

SELECT portfolio_id, MIN(purchase_date) AS oldest_purchase_date
FROM portfolio_instruments
GROUP BY portfolio_id;

SELECT portfolios.portfolio_name, portfolios.status
FROM portfolios
WHERE portfolios.return_percentage > (
  SELECT MIN(portfolio_instruments.return_percentage)
  FROM portfolio_instruments
);

